# frozen_string_literal: true

require "spec_helper"

RSpec.describe "MCP type coercion" do
  let(:test_class) do
    Class.new do
      include Raix::ChatCompletion
      include Raix::MCP

      def self.name
        "TestMcpTypeCoercion"
      end
    end
  end

  it "coerces string numbers to numeric types based on schema" do
    instance = test_class.new

    # Test integer coercion
    schema = {
      "properties" => {
        "x" => { "type" => "integer" },
        "y" => { "type" => "number" },
        "enabled" => { "type" => "boolean" },
        "items" => { "type" => "array" },
        "data" => { "type" => "object" }
      }
    }

    arguments = {
      "x" => "100",
      "y" => "50.5",
      "enabled" => "true",
      "items" => "[1, 2, 3]",
      "data" => '{"key": "value"}'
    }

    result = instance.send(:coerce_arguments, arguments, schema)

    expect(result["x"]).to eq(100)
    expect(result["x"]).to be_a(Integer)

    expect(result["y"]).to eq(50.5)
    expect(result["y"]).to be_a(Float)

    expect(result["enabled"]).to eq(true)
    expect(result["enabled"]).to be_a(TrueClass)

    expect(result["items"]).to eq([1, 2, 3])
    expect(result["items"]).to be_a(Array)

    expect(result["data"]).to eq({ "key" => "value" })
    expect(result["data"]).to be_a(Hash)
  end

  it "preserves non-string values" do
    instance = test_class.new

    schema = {
      "properties" => {
        "x" => { "type" => "integer" },
        "y" => { "type" => "number" }
      }
    }

    arguments = { "x" => 100, "y" => 50.5 }
    result = instance.send(:coerce_arguments, arguments, schema)

    expect(result["x"]).to eq(100)
    expect(result["y"]).to eq(50.5)
  end

  it "coerces arrays of objects with item schemas" do
    instance = test_class.new

    schema = {
      "properties" => {
        "users" => {
          "type" => "array",
          "items" => {
            "type" => "object",
            "properties" => {
              "id" => { "type" => "integer" },
              "age" => { "type" => "number" },
              "active" => { "type" => "boolean" }
            }
          }
        }
      }
    }

    arguments = {
      "users" => [
        { "id" => "123", "age" => "25.5", "active" => "true" },
        { "id" => "456", "age" => "30", "active" => "false" }
      ]
    }

    result = instance.send(:coerce_arguments, arguments, schema)

    expect(result["users"]).to be_a(Array)
    expect(result["users"].length).to eq(2)

    first_user = result["users"][0]
    expect(first_user["id"]).to eq(123)
    expect(first_user["id"]).to be_a(Integer)
    expect(first_user["age"]).to eq(25.5)
    expect(first_user["age"]).to be_a(Float)
    expect(first_user["active"]).to eq(true)
    expect(first_user["active"]).to be_a(TrueClass)

    second_user = result["users"][1]
    expect(second_user["id"]).to eq(456)
    expect(second_user["active"]).to eq(false)
  end

  it "handles nested object coercion" do
    instance = test_class.new

    schema = {
      "properties" => {
        "config" => {
          "type" => "object",
          "properties" => {
            "settings" => {
              "type" => "object",
              "properties" => {
                "max_retries" => { "type" => "integer" },
                "timeout" => { "type" => "number" },
                "debug" => { "type" => "boolean" }
              }
            },
            "metadata" => {
              "type" => "object",
              "properties" => {
                "version" => { "type" => "number" }
              }
            }
          }
        }
      }
    }

    arguments = {
      "config" => {
        "settings" => {
          "max_retries" => "3",
          "timeout" => "30.5",
          "debug" => "true"
        },
        "metadata" => {
          "version" => "1.2"
        }
      }
    }

    result = instance.send(:coerce_arguments, arguments, schema)

    expect(result["config"]["settings"]["max_retries"]).to eq(3)
    expect(result["config"]["settings"]["max_retries"]).to be_a(Integer)
    expect(result["config"]["settings"]["timeout"]).to eq(30.5)
    expect(result["config"]["settings"]["timeout"]).to be_a(Float)
    expect(result["config"]["settings"]["debug"]).to eq(true)
    expect(result["config"]["metadata"]["version"]).to eq(1.2)
  end

  it "handles JSON string inputs for arrays and objects" do
    instance = test_class.new

    schema = {
      "properties" => {
        "tags" => { "type" => "array" },
        "config" => {
          "type" => "object",
          "properties" => {
            "enabled" => { "type" => "boolean" }
          }
        }
      }
    }

    arguments = {
      "tags" => '["tag1", "tag2", "tag3"]',
      "config" => '{"enabled": "true", "extra": "value"}'
    }

    result = instance.send(:coerce_arguments, arguments, schema)

    expect(result["tags"]).to eq(%w[tag1 tag2 tag3])
    expect(result["config"]["enabled"]).to eq(true)
    expect(result["config"]["extra"]).to eq("value") # preserves extra properties
  end

  it "handles invalid JSON gracefully" do
    instance = test_class.new

    schema = {
      "properties" => {
        "data" => { "type" => "array" }
      }
    }

    arguments = {
      "data" => "not valid json ["
    }

    result = instance.send(:coerce_arguments, arguments, schema)

    # Should return the original value when JSON parsing fails
    expect(result["data"]).to eq("not valid json [")
  end

  it "handles type mismatches gracefully" do
    instance = test_class.new

    schema = {
      "properties" => {
        "count" => { "type" => "integer" },
        "ratio" => { "type" => "number" },
        "flag" => { "type" => "boolean" }
      }
    }

    arguments = {
      "count" => "not a number",
      "ratio" => "also not a number",
      "flag" => "maybe"
    }

    result = instance.send(:coerce_arguments, arguments, schema)

    # Should return original values when coercion is not possible
    expect(result["count"]).to eq("not a number")
    expect(result["ratio"]).to eq("also not a number")
    expect(result["flag"]).to eq("maybe")
  end

  it "preserves additional properties not in schema" do
    instance = test_class.new

    schema = {
      "properties" => {
        "known" => { "type" => "integer" }
      }
    }

    arguments = {
      "known" => "42",
      "unknown" => "value",
      "extra" => { "nested" => true }
    }

    result = instance.send(:coerce_arguments, arguments, schema)

    expect(result["known"]).to eq(42)
    expect(result["unknown"]).to eq("value")
    expect(result["extra"]).to eq({ "nested" => true })
  end

  it "handles symbol and string keys interchangeably" do
    instance = test_class.new

    schema = {
      "properties" => {
        "value" => { "type" => "integer" }
      }
    }

    arguments = {
      value: "100" # symbol key
    }

    result = instance.send(:coerce_arguments, arguments, schema)

    expect(result["value"]).to eq(100)
    expect(result[:value]).to eq(100) # with_indifferent_access allows both
  end

  it "handles nil values appropriately" do
    instance = test_class.new

    schema = {
      "properties" => {
        "optional_int" => { "type" => "integer" },
        "optional_bool" => { "type" => "boolean" }
      }
    }

    arguments = {
      "optional_int" => nil,
      "other_field" => "value"
    }

    result = instance.send(:coerce_arguments, arguments, schema)

    # nil values are preserved as-is (not coerced)
    expect(result["optional_int"]).to be_nil
    expect(result["other_field"]).to eq("value")
  end

  it "coerces boolean edge cases correctly" do
    instance = test_class.new

    schema = {
      "properties" => {
        "bool1" => { "type" => "boolean" },
        "bool2" => { "type" => "boolean" },
        "bool3" => { "type" => "boolean" },
        "bool4" => { "type" => "boolean" }
      }
    }

    arguments = {
      "bool1" => true,
      "bool2" => false,
      "bool3" => "true",
      "bool4" => "false"
    }

    result = instance.send(:coerce_arguments, arguments, schema)

    expect(result["bool1"]).to eq(true)
    expect(result["bool2"]).to eq(false)
    expect(result["bool3"]).to eq(true)
    expect(result["bool4"]).to eq(false)
  end
end

RSpec.describe "MCP function name mapping" do
  let(:test_class) do
    Class.new do
      include Raix::ChatCompletion
      include Raix::MCP

      attr_accessor :transcript

      def initialize
        @transcript = []
      end

      def self.name
        "TestMcpFunctionNames"
      end

      def chat_completion_args
        {}
      end

      def loop
        false
      end
    end
  end

  it "uses local_name with prefix in transcript instead of remote_name" do
    client_key = "client_key"
    mock_tool = OpenStruct.new(
      name: "get_data",
      description: "Gets some data",
      input_schema: {
        "properties" => {
          "id" => { "type" => "integer" }
        }
      }
    )
    mock_client = double("MCP::StdioClient",
                         unique_key: client_key,
                         close: nil,
                         tools: [mock_tool])

    data_result = "Data for ID 123"
    allow(mock_client).to receive(:call_tool).with("get_data", id: 123).and_return(data_result)
    test_class.mcp(client: mock_client)
    instance = test_class.new

    local_method_name = :get_data_client_key
    expect(instance).to respond_to(local_method_name)

    result = instance.send(local_method_name, { id: "123" }, nil)
    expect(result).to eq(data_result)

    expect(instance.transcript.size).to eq(1)
    messages = instance.transcript[0]
    expect(messages).to be_an(Array)
    expect(messages.size).to eq(2)

    assistant_msg = messages[0]
    expect(assistant_msg[:role]).to eq("assistant")
    expect(assistant_msg[:tool_calls][0][:function][:name]).to eq("get_data_#{client_key}")

    tool_msg = messages[1]
    expect(tool_msg[:role]).to eq("tool")
    expect(tool_msg[:name]).to eq("get_data_#{client_key}")
  end
end

# frozen_string_literal: true

require "spec_helper"

RSpec.describe Raix::MessageAdapters::Base do
  let(:context) { double("Context", model: "anthropic/claude-3", cache_at: 10) }
  let(:adapter) { described_class.new(context) }

  describe "#transform" do
    it "returns the message if it already has a role" do
      message = { role: "user", content: "Hello" }
      expect(adapter.transform(message)).to eq(message)
    end

    it "transforms a function call message" do
      message = { function: { name: "my_function", arguments: { param: "value" } } }
      expected = { role: "assistant", name: "my_function", content: { param: "value" }.to_json }
      expect(adapter.transform(message)).to eq(expected)
    end

    it "transforms a result message" do
      message = { result: "Hello", name: "my_function" }
      expected = { role: "function", name: "my_function", content: "Hello" }
      expect(adapter.transform(message)).to eq(expected)
    end

    it "transforms a message with a single key-value pair" do
      message = { user: "Hello" }
      expected = { role: "user", content: "Hello" }
      expect(adapter.transform(message)).to eq(expected)
    end

    it "transforms a message with a large content" do
      message = { user: "Hello" * 5 }
      expected = { role: "user", content: [{ type: "text", text: "Hello" * 5, cache_control: { type: "ephemeral" } }] }
      expect(adapter.transform(message)).to eq(expected)
    end
  end
end

# frozen_string_literal: true

require "json"

# Test MCP Server implementing the Model Context Protocol over stdio transport
# This server provides several test tools for validating the StdioClient functionality
class TestMCPServer
  JSONRPC_VERSION = "2.0"

  def initialize
    $stdout.sync = true # Enable auto-flushing for immediate output
    @tools = build_tools
  end

  def run
    # Read JSON-RPC requests from stdin and respond on stdout
    while (line = $stdin.gets)
      begin
        request = JSON.parse(line.strip)
        response = handle_request(request)
        puts response.to_json if response
      rescue JSON::ParserError => e
        error_response = create_error_response(nil, -32_700, "Parse error: #{e.message}")
        puts error_response.to_json
      rescue StandardError => e
        error_response = create_error_response(request&.dig("id"), -32_603, "Internal error: #{e.message}")
        puts error_response.to_json
      end
    end
  end

  private

  def create_response(id:, result: nil, error: nil)
    {
      jsonrpc: JSONRPC_VERSION,
      id:,
      result:,
      error:
    }.compact
  end

  def create_error_response(id, code, message)
    create_response(id:, error: { code:, message: })
  end

  def handle_request(request)
    method = request["method"]
    params = request["params"] || {}
    id = request["id"]

    case method
    when "tools/list"
      handle_tools_list(id)
    when "tools/call"
      handle_tools_call(id, params)
    else
      create_error_response(id, -32_601, "Method not found: #{method}")
    end
  end

  def handle_tools_list(id)
    tools_without_handlers = @tools.values.map do |tool|
      tool.except("handler")
    end
    create_response(id:, result: { tools: tools_without_handlers })
  end

  def handle_tools_call(id, params)
    tool_name = params["name"]
    arguments = params["arguments"] || {}

    tool = @tools[tool_name]
    unless tool
      return create_error_response(id, -32_602, "Unknown tool: #{tool_name}")
    end

    begin
      content = tool["handler"].call(arguments)
      create_response(id:, result: { content: })
    rescue ArgumentError => e
      create_error_response(id, -32_602, "Invalid parameters: #{e.message}")
    end
  end

  def build_tools
    {
      "ping" => {
        "name" => "ping",
        "description" => "Returns 'pong' - useful for testing connectivity",
        "inputSchema" => {
          "type" => "object",
          "properties" => {},
          "required" => []
        },
        "handler" => ->(_args) { [{ type: "text", text: "pong" }] }
      },
      "echo" => {
        "name" => "echo",
        "description" => "Echoes back the provided message",
        "inputSchema" => {
          "type" => "object",
          "properties" => {
            "message" => {
              "type" => "string",
              "description" => "The message to echo back"
            }
          },
          "required" => ["message"]
        },
        "handler" => lambda { |args|
          raise ArgumentError, "Missing required parameter: message" unless args["message"]

          [{ type: "text", text: args["message"] }]
        }
      },
      "process_data" => {
        "name" => "process_data",
        "description" => "Processes complex data structures",
        "inputSchema" => {
          "type" => "object",
          "properties" => {
            "data" => {
              "type" => "object",
              "description" => "Complex data to process"
            }
          },
          "required" => ["data"]
        },
        "handler" => lambda { |args|
          raise ArgumentError, "Missing required parameter: data" unless args["data"]

          [{
            type: "text",
            text: JSON.generate({ processed: true, original: args["data"] })
          }]
        }
      },
      "binary_data" => {
        "name" => "binary_data",
        "description" => "Returns binary data (for testing non-text content)",
        "inputSchema" => {
          "type" => "object",
          "properties" => {},
          "required" => []
        },
        "handler" => ->(_args) { [{ type: "image", data: "base64encodeddata" }] }
      }
    }
  end
end

# Run the server if this file is executed directly
if __FILE__ == $PROGRAM_NAME
  server = TestMCPServer.new
  server.run
end
